import json
import os
from datetime import datetime, timezone

CORS_ALLOW_ORIGIN = os.getenv("CORS_ALLOW_ORIGIN", "*")
CORS_ALLOW_HEADERS = os.getenv(
    "CORS_ALLOW_HEADERS",
    "Content-Type,Authorization,X-Amz-Date,X-Api-Key,X-Amz-Security-Token,X-Requested-With",
)
CORS_ALLOW_METHODS = os.getenv("CORS_ALLOW_METHODS", "GET,OPTIONS")
CORS_MAX_AGE = os.getenv("CORS_MAX_AGE", "86400")


def _cors_headers(origin=None):
    allow_origin = CORS_ALLOW_ORIGIN
    if allow_origin != "*" and origin:
        allow_origin = origin

    return {
        "Access-Control-Allow-Origin": allow_origin,
        "Access-Control-Allow-Headers": CORS_ALLOW_HEADERS,
        "Access-Control-Allow-Methods": CORS_ALLOW_METHODS,
        "Access-Control-Max-Age": CORS_MAX_AGE,
        "Access-Control-Allow-Credentials": "false",
        "Vary": "Origin",
        "Content-Type": "application/json",
    }


def _response(status_code, body, origin=None, extra_headers=None):
    headers = _cors_headers(origin)
    if extra_headers:
        headers.update(extra_headers)
    return {
        "statusCode": status_code,
        "headers": headers,
        "body": json.dumps(body, separators=(",", ":"), default=str),
    }


def _get_origin(event):
    headers = event.get("headers") or {}
    return headers.get("origin") or headers.get("Origin")


def _get_user_id(event):
    qs = event.get("queryStringParameters") or {}
    if "userId" in qs and qs["userId"]:
        return str(qs["userId"])

    path_params = event.get("pathParameters") or {}
    if "userId" in path_params and path_params["userId"]:
        return str(path_params["userId"])

    rc = event.get("requestContext") or {}
    authorizer = rc.get("authorizer") or {}
    claims = authorizer.get("claims") or {}
    if "sub" in claims and claims["sub"]:
        return str(claims["sub"])

    return "demo-user"


def handler(event, context):
    origin = _get_origin(event)
    method = (event.get("httpMethod") or "").upper()

    if method == "OPTIONS":
        return _response(204, "", origin, extra_headers={"Content-Type": "text/plain"})

